(window.webpackJsonp=window.webpackJsonp||[]).push([[306],{1557:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * Definition for singly-linked list.\\n * function ListNode(val, next) {\\n *     this.val = (val===undefined ? 0 : val)\\n *     this.next = (next===undefined ? null : next)\\n * }\\n */</span>\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{ListNode}</span> <span class=\\"hljs-variable\\">head</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">left</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">right</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{ListNode}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> reverseBetween = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">head, left, right</span>) </span>{\\n    <span class=\\"hljs-keyword\\">if</span>(left===right)<span class=\\"hljs-keyword\\">return</span> head\\n    <span class=\\"hljs-keyword\\">let</span> headNode=<span class=\\"hljs-literal\\">null</span>\\n    <span class=\\"hljs-keyword\\">let</span> lastNode=<span class=\\"hljs-literal\\">null</span>\\n    <span class=\\"hljs-keyword\\">let</span> lastEnd=<span class=\\"hljs-literal\\">null</span>\\n    <span class=\\"hljs-keyword\\">let</span> root=<span class=\\"hljs-keyword\\">new</span> ListNode()\\n    root.next=head\\n    <span class=\\"hljs-keyword\\">let</span> curRoot=root\\n    <span class=\\"hljs-keyword\\">let</span> step=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">while</span>(curRoot){\\n        step++\\n        <span class=\\"hljs-keyword\\">let</span> nextNode=curRoot.next\\n        <span class=\\"hljs-keyword\\">if</span>(step===left){\\n            headNode=curRoot\\n            lastNode=curRoot.next\\n            lastEnd=lastNode\\n        }<span class=\\"hljs-keyword\\">else</span> <span class=\\"hljs-keyword\\">if</span>(step&gt;left+<span class=\\"hljs-number\\">1</span> &amp;&amp; step&lt;=right+<span class=\\"hljs-number\\">1</span>){\\n            <span class=\\"hljs-comment\\">// console.log(headNode,curRoot.val,lastNode.val,nextNode)</span>\\n            headNode.next=curRoot\\n            curRoot.next=lastNode\\n            lastEnd.next=nextNode\\n            lastNode=headNode.next\\n        }\\n        curRoot=nextNode\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> root.next\\n};\\n</code></pre>\\n"],"titleSlug":"reverse-linked-list-ii","hasThinking":true,"thinking":"<hr>\\n<p>\u601d\u8def\uff1a</p>\\n<p>\u53cd\u8f6c\u94fe\u8868\u9700\u8981\u4e00\u4e2a\u4e00\u4e2a\u8282\u70b9\u6765\u5904\u7406\u3002</p>\\n<p>\u4f8b\u5982 <code>[1-&gt;2-&gt;3-&gt;4-&gt;5],m=2,n=4</code></p>\\n<p>\u53cd\u8f6c\u4ece\u7b2c<code>2</code>\u4e2a\u8282\u70b9\u5f00\u59cb\uff0c\u6211\u4eec\u9996\u5148\u8981\u627e\u5230\u5934\u90e8\u8282\u70b9(\u7b2c<code>1</code>\u4e2a\u8282\u70b9)\uff0c\u56e0\u4e3a\u540e\u7eed\u6240\u6709\u7684\u53cd\u8f6c\u90fd\u662f\u5728\u7b2c<code>1</code>\u4e2a\u8282\u70b9\u7684<code>next</code>\u4e0a\u5904\u7406\u7684\u3002</p>\\n<p>\u540c\u65f6\uff0c\u6211\u4eec\u9700\u8981\u627e\u5230\u4e00\u4e2a\u5c3e\u5df4\u8282\u70b9\uff0c\u4f8b\u5982\u53cd\u8f6c<code>3</code>\u7684\u65f6\u5019\uff0c\u8282\u70b9<code>2</code>\u5c31\u662f\u5c3e\u5df4\u8282\u70b9\uff0c\u5b83\u7684\u4f5c\u7528\u5c31\u662f\u5c06\u8981\u53cd\u8f6c\u7684<code>3</code>\u540e\u9762\u7684\u8282\u70b9\u8fde\u63a5\u8d77\u6765\u3002</p>\\n<p>\u8fd9\u4e24\u4e2a\u8282\u70b9<code>\u5934\u90e8\u8282\u70b9(1)</code>\u548c<code>\u5c3e\u5df4\u8282\u70b9(2)</code>\u662f\u4e0d\u53d8\u7684\u3002</p>\\n<p>\u5f53\u53cd\u8f6c<code>3</code>\u65f6\uff0c\u5c06<code>1</code>\u548c<code>3</code>\u76f8\u8fde\uff0c<code>3</code>\u548c<code>2</code>\u76f8\u8fde\uff0c<code>2</code>\u548c<code>4</code>\u76f8\u8fde\uff1b</p>\\n<p>\u5f53\u53cd\u8f6c<code>4</code>\u65f6\uff0c\u5c06<code>1</code>\u548c<code>4</code>\u76f8\u8fde\uff0c<code>4</code>\u548c<code>3</code>\u76f8\u8fde\uff0c<code>2</code>\u548c<code>5</code>\u76f8\u8fde\u3002</p>\\n","content":"\u7ed9\u4f60\u5355\u94fe\u8868\u7684\u5934\u6307\u9488 <code>head</code> \u548c\u4e24\u4e2a\u6574\u6570\xa0<code>left</code> \u548c <code>right</code> \uff0c\u5176\u4e2d\xa0<code>left <= right</code> \u3002\u8bf7\u4f60\u53cd\u8f6c\u4ece\u4f4d\u7f6e <code>left</code> \u5230\u4f4d\u7f6e <code>right</code> \u7684\u94fe\u8868\u8282\u70b9\uff0c\u8fd4\u56de <strong>\u53cd\u8f6c\u540e\u7684\u94fe\u8868</strong> \u3002\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2021/02/19/rev2ex2.jpg\\" style=\\"width: 542px; height: 222px;\\" />\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>head = [1,2,3,4,5], left = 2, right = 4\\n<strong>\u8f93\u51fa\uff1a</strong>[1,4,3,2,5]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>head = [5], left = 1, right = 1\\n<strong>\u8f93\u51fa\uff1a</strong>[5]\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li>\u94fe\u8868\u4e2d\u8282\u70b9\u6570\u76ee\u4e3a <code>n</code></li>\\n\\t<li><code>1 <= n <= 500</code></li>\\n\\t<li><code>-500 <= Node.val <= 500</code></li>\\n\\t<li><code>1 <= left <= right <= n</code></li>\\n</ul>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u8fdb\u9636\uff1a</strong> \u4f60\u53ef\u4ee5\u4f7f\u7528\u4e00\u8d9f\u626b\u63cf\u5b8c\u6210\u53cd\u8f6c\u5417\uff1f</p>\\n","title":"92. \u53cd\u8f6c\u94fe\u8868 II","relatedTags":["\u94fe\u8868"],"difficult":"Middle","lang":["javascript"],"uniqueID":"92"}')}}]);